class Solution {
    public int maxVowels(String s, int k) {
        int maxVowels = 0;
        for (int i = 0; i <= s.length() - k; i++) {
            int vowelCount = 0;
            for (int j = i; j < i + k; j++) {
                if (s.charAt(j) == 'a' || s.charAt(j) == 'e' || s.charAt(j) == 'i' || s.charAt(j) == 'o' || s.charAt(j) == 'u') {
                    vowelCount++;
                }
            }
            maxVowels = Math.max(maxVowels, vowelCount);
        }
        return maxVowels;
    }
}
